import{_ as t,c as n,o as r,a1 as a}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"Plattformintegration: Unterstützung mehrerer Protokolle | Antigravity-Manager","description":"Erfahre, wie du Antigravity Tools für die Integration von Plattformprotokollen verwendest. Unterstützt die einheitliche API-Gateway-Umwandlung für 7 Protokolle wie OpenAI, Anthropic, Gemini und mehr.","frontmatter":{"title":"Plattformintegration: Unterstützung mehrerer Protokolle | Antigravity-Manager","sidebarTitle":"Verbinde deine KI-Plattformen","subtitle":"Plattformintegration: Unterstützung mehrerer Protokolle","description":"Erfahre, wie du Antigravity Tools für die Integration von Plattformprotokollen verwendest. Unterstützt die einheitliche API-Gateway-Umwandlung für 7 Protokolle wie OpenAI, Anthropic, Gemini und mehr.","order":200},"headers":[],"relativePath":"de/lbjlaq/Antigravity-Manager/platforms/index.md","filePath":"de/lbjlaq/Antigravity-Manager/platforms/index.md"}'),i={name:"de/lbjlaq/Antigravity-Manager/platforms/index.md"};function o(d,e,l,s,h,u){return r(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="plattformen-und-integrationen" tabindex="-1">Plattformen und Integrationen <a class="header-anchor" href="#plattformen-und-integrationen" aria-label="Permalink to &quot;Plattformen und Integrationen&quot;">​</a></h1><p>Die Kernfunktion von Antigravity Tools ist die Konvertierung mehrerer KI-Plattformprotokolle in ein einheitliches lokales API-Gateway. Dieses Kapitel beschreibt im Detail die Integrationsmethoden, Kompatibilitätsgrenzen und bewährte Praktiken für jedes Protokoll.</p><h2 id="inhalt-dieses-kapitels" tabindex="-1">Inhalt dieses Kapitels <a class="header-anchor" href="#inhalt-dieses-kapitels" aria-label="Permalink to &quot;Inhalt dieses Kapitels&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tutorial</th><th>Beschreibung</th></tr></thead><tbody><tr><td><a href="./openai/">OpenAI-kompatible API</a></td><td>Implementierungsstrategien für <code>/v1/chat/completions</code> und <code>/v1/responses</code>, nahtlose Integration mit OpenAI SDK</td></tr><tr><td>---</td><td>---</td></tr><tr><td><a href="./gemini/">Gemini Native API</a></td><td><code>/v1beta/models</code> und Google SDK Endpunkte, unterstützt <code>x-goog-api-key</code> Kompatibilität</td></tr><tr><td><a href="./imagen/">Imagen 3 Bildgenerierung</a></td><td>Automatische Abbildung von OpenAI Images-Parametern <code>size</code>/<code>quality</code>, unterstützt beliebige Seitenverhältnisse</td></tr><tr><td><a href="./audio/">Audio-Transkription</a></td><td>Einschränkungen von <code>/v1/audio/transcriptions</code> und Verarbeitung großer Datenvolumen</td></tr><tr><td><a href="./mcp/">MCP Endpunkte</a></td><td>Web Search/Reader/Vision als aufrufbare Tools verfügbar machen</td></tr><tr><td><a href="./cloudflared/">Cloudflared Tunnel</a></td><td>Ein-Klick-Exposition der lokalen API ins öffentliche Internet (nicht standardmäßig sicher)</td></tr></tbody></table><h2 id="empfohlener-lernpfad" tabindex="-1">Empfohlener Lernpfad <a class="header-anchor" href="#empfohlener-lernpfad" aria-label="Permalink to &quot;Empfohlener Lernpfad&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Empfohlene Reihenfolge</p><ol><li><strong>Lerne zuerst das von dir verwendete Protokoll</strong>: Wenn du Claude Code verwendest, lies zuerst <a href="./anthropic/">Anthropic-kompatible API</a>; wenn du OpenAI SDK verwendest, lies zuerst <a href="./openai/">OpenAI-kompatible API</a></li><li><strong>Dann lerne Gemini Native</strong>: Verstehe die direkte Integrationsmethode des Google SDK</li><li><strong>Lerne Erweiterungsfunktionen nach Bedarf</strong>: Bildgenerierung, Audio-Transkription, MCP-Tools</li><li><strong>Zuletzt lerne Tunnel</strong>: Lies <a href="./cloudflared/">Cloudflared Tunnel</a>, wenn du eine öffentliche Exposition benötigst</li></ol></div><p><strong>Schnellauswahl</strong>:</p><table tabindex="0"><thead><tr><th>Dein Szenario</th><th>Empfohlen, zuerst zu lesen</th></tr></thead><tbody><tr><td>Verwendung von Claude Code CLI</td><td><a href="./anthropic/">Anthropic-kompatible API</a></td></tr><tr><td>Verwendung von OpenAI Python SDK</td><td><a href="./openai/">OpenAI-kompatible API</a></td></tr><tr><td>Verwendung von Google offiziellem SDK</td><td><a href="./gemini/">Gemini Native API</a></td></tr><tr><td>Benötigst du KI-Bilderzeugung</td><td><a href="./imagen/">Imagen 3 Bildgenerierung</a></td></tr><tr><td>---</td><td>---</td></tr><tr><td>Benötigst du Internetsuche/Weblesen</td><td><a href="./mcp/">MCP Endpunkte</a></td></tr><tr><td>Benötigst du Remote-Zugriff</td><td><a href="./cloudflared/">Cloudflared Tunnel</a></td></tr></tbody></table><h2 id="voraussetzungen" tabindex="-1">Voraussetzungen <a class="header-anchor" href="#voraussetzungen" aria-label="Permalink to &quot;Voraussetzungen&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Vor dem Start bitte bestätigen</p><ul><li><a href="./../start/installation/">Installation und Upgrade</a> abgeschlossen</li><li><a href="./../start/add-account/">Konto hinzufügen</a> abgeschlossen</li><li><a href="./../start/proxy-and-first-client/">Lokalen Reverse-Proxy starten</a> abgeschlossen (mindestens Zugriff auf <code>/healthz</code>)</li></ul></div><h2 id="nachste-schritte" tabindex="-1">Nächste Schritte <a class="header-anchor" href="#nachste-schritte" aria-label="Permalink to &quot;Nächste Schritte&quot;">​</a></h2><p>Nach Abschluss dieses Kapitels kannst du weiter lernen:</p><ul><li><a href="./../advanced/">Erweiterte Konfiguration</a>: Modell-Routing, Quotenverwaltung, Hochverfügbarkeitsplanung und andere erweiterte Funktionen</li><li><a href="./../faq/">Häufig gestellte Fragen</a>: Fehlerbehebungsleitfaden für 401/404/429 und andere Fehler</li></ul>',13)])])}const f=t(i,[["render",o]]);export{c as __pageData,f as default};
